import React from 'react'

import {Link,BrowserRouter,Switch,Route } from 'react-router-dom'

import Title from './Title';

import CharCreator from '../CharCreator/CharCreator'
import Download from '../helper/Download'

function MainMenu(){
	return(
		<BrowserRouter>
			<Switch>
				<Route path="/CharCreator">
			        <CharCreator/>
			    </Route>
			    <Route path="/">
			    <div class="link-group">
					<Title/>
				    <button><Link to="/CharCreator">Character creator</Link></button>
					<button><Link to="/tile_map_creator/index.html">Tile Map Creator</Link></button>
					<Download/>
		        	</div>
			    </Route>
		    </Switch>
			
        </BrowserRouter>
	);
}

export default MainMenu