import React, {Component} from 'react'

import Title from './Title';
import CharSheet from './CharSheet'

class CharCreator extends Component{
	name="test"
	changeName=function(){
		this.name="changed"
	}
	render(){
		return (
			<React.Fragment>
				<Title/>
				<CharSheet name={this.name}/>
			</React.Fragment>
		);
	}
}

export default CharCreator

